INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3ce2a203-3670-4f5d-8143-85967350e701',
  '00000000-0000-0000-0000-000000000001',
  $escape$Oauth2 Token Encryption: Symmetric vs Asymmetric Keys$escape$,
  $escape$Oauth2 token encryption relies on symmetric or asymmetric encryption. Symmetric encryption (e.g., AES) uses the same key for encryption and decryption. Asymmetric encryption (e.g., RSA) uses a public key for encryption and a private key for decryption. Oauth2 token encryption typically uses symmetric keys. For example, the OAuth 2.0 Token Endpoint Response (RFC 6749, Section 5.1) specifies using symmetric encryption for token encryption. When choosing symmetric keys, ensure they are randomly generated and securely stored.$escape$,
  $escape$const crypto = require('crypto');
const key = crypto.randomBytes(32);
const encryptedToken = crypto.createCipheriv('aes-256-cbc', key, Buffer.alloc(16)).update('your_token', 'utf8', 'hex');
const decryptedToken = crypto.createDecipheriv('aes-256-cbc', key, Buffer.alloc(16)).update(encryptedToken, 'hex', 'utf8');$escape$,
  $escape$javascript$escape$,
