INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e053d3da-0585-4fc5-9064-cc449d64fa90',
  '00000000-0000-0000-0000-000000000001',
  $escape$oauth2 Certificate Management - CA vs Self-Signed with Let's Encrypt$escape$,
  $escape$When using OAuth2, certificate management is crucial for maintaining the security and integrity of your authentication flow. OAuth2 relies on TLS to encrypt client-server communication. You can obtain certificates from a Certificate Authority (CA) or create self-signed certificates. However, self-signed certificates are not trusted by default and may lead to client-side errors. Let's Encrypt is a popular CA that offers free certificates, which can be automated for renewal using ACME protocol. To obtain a certificate from Let's Encrypt, you'll need to implement an ACME client, which will handle the certificate renewal process for you.$escape$,
  NULL,
  NULL,
