INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7359d97b-fd0e-442c-ac82-768e0a625739',
  '00000000-0000-0000-0000-000000000001',
  $escape$oauth2 - TLS in OAuth 2.0 Resource Servers$escape$,
  $escape$When a client initiates an OAuth 2.0 authorization request, the resource server responds with an HTTP redirect to the authorization endpoint. This redirect is secured with TLS (Transport Layer Security). To establish a secure connection, the client and resource server perform a TLS handshake, exchanging certificates and cipher suites. OAuth 2.0 specifies TLS 1.2 as the minimum version for secure connections, but TLS 1.3 is also supported. To ensure compatibility with older clients, some resource servers may still use TLS 1.2. When using the `bearer` token type, clients must use a secure transport layer, such as TLS, to prevent token interception.$escape$,
  NULL,
  NULL,
