INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7936842b-df1c-4f10-822e-9ad7ebbdf590',
  '00000000-0000-0000-0000-000000000001',
  $escape$oauth2: JWT Structure and Validation$escape$,
  $escape$In an oauth2 JWT, the structure consists of a header, payload, and signature. The header contains the algorithm used for signing, payload contains claims like issuer, audience, and scopes, while the signature is a base64 encoded hash of the header and payload. oauth2 specifies two common signing algorithms: HS256 (HMAC SHA256) and RS256 (RSA SHA256). HS256 uses a shared secret key, whereas RS256 uses a public-private key pair. When validating a JWT, the client must verify the signature, check the issuer and audience, and ensure the token is not expired.$escape$,
  $escape$import jwt from 'jsonwebtoken';

const token = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzdWIiOiIxMjM0NTY3ODkwIiwibmFtZSI6IkpvaG4gRG9lIiwiaWF0IjoxNTE2MjM5MDIyfQ.SflKxwRJSMeKKF2QT4fwpMeJf36POk6yJV_adQssw5c';

try {
  const decoded = jwt.verify(token, 'your-secret-key');
  console.log(decoded);
} catch (error) {
  console.error(error);
}$escape$,
  $escape$javascript$escape$,
