INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '87b5296e-02b4-447c-ab0e-756f283316da',
  '00000000-0000-0000-0000-000000000001',
  $escape$oauth2 and FIPS 140-2: Ensuring Cryptographic Compliance$escape$,
  $escape$When implementing oauth2, ensuring compliance with FIPS 140-2 is crucial, especially for cryptographic operations. oauth2 clients and servers use symmetric encryption for token signing (e.g., HS256) and asymmetric encryption for token encryption (e.g., RSA-OAEP). To comply with FIPS 140-2, use an FIPS 140-2 validated module for encryption operations. Specifically, when using the oauth2 'token_endpoint' for client authentication, ensure that the symmetric encryption key used is FIPS 140-2 compliant. This includes using a 256-bit AES key with a 128-bit key wrapped with a FIPS 140-2 compliant wrapper.$escape$,
  NULL,
  NULL,
