INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'efd1352e-aed0-4b46-afa9-da158edec689',
  '00000000-0000-0000-0000-000000000001',
  $escape$oauth2 — ID Tokens vs Access Tokens: A Userinfo Endpoint Guide$escape$,
  $escape$When using OpenID Connect (OIDC) with oauth2, you'll encounter two types of tokens: ID tokens and access tokens. ID tokens contain user information and are signed with the client's secret key. Access tokens, on the other hand, grant access to protected resources. The userinfo endpoint provides an efficient way to retrieve user information from the ID token without requiring the client to store or manage user data. To use the userinfo endpoint, append the client ID and the ID token to the userinfo endpoint URL, as shown below.

const idToken = 'your_id_token_here';
const clientId = 'your_client_id_here';
const userinfoEndpoint = 'https://your-authority/oauth2/v2.0/userinfo';

fetch(`${userinfoEndpoint}?client_id=${clientId}&id_token=${idToken}`)
  .then(response => response.json())
  .then(data => console.log(data))$escape$,
  $escape$javascript$escape$,
  $escape$javascript$escape$,
